import { CloudArrowUpFillIcon } from "@lifesg/react-icons/cloud-arrow-up-fill";
import clsx from "clsx";
import type React from "react";
import { forwardRef, useImperativeHandle, useRef } from "react";
import { useDropzone } from "react-dropzone";

import { DashedBorder } from "../dashed-border";
import { Border, Colour, Radius } from "../theme";
import { Typography } from "../typography";
import * as styles from "./dropzone.styles";
import type { FileInputProps } from "./types";

export interface DropzoneElement extends HTMLInputElement {
    openFileDialog: () => void;
}

interface Props extends FileInputProps {
    children: React.ReactNode;
    id: string;
    border: boolean;
    onChange: (files: File[]) => void;
}

const Component = (
    {
        children,
        accept,
        capture,
        multiple,
        id,
        className,
        name,
        border,
        disabled,
        onChange,
        "data-testid": testId,
    }: Props,
    ref: React.Ref<DropzoneElement>
) => {
    // =========================================================================
    // CONST, STATE, REFS
    // =========================================================================
    const inputRef = useRef<HTMLInputElement>(null);
    const { getRootProps, isDragActive } = useDropzone({
        onDrop: onChange,
        noClick: true,
        disabled,
    });

    useImperativeHandle(ref, () => ({
        ...inputRef.current!,
        openFileDialog: () => {
            if (inputRef.current) {
                inputRef.current.value = ""; // Reset the input to enable same file upload
                inputRef.current.click();
            }
        },
    }));

    // =========================================================================
    // EVENT HANDLERS
    // =========================================================================
    const handleChange = (event: React.ChangeEvent<HTMLInputElement>) => {
        if (event.target.files) {
            onChange(Array.from(event.target.files));
        }
    };

    // =========================================================================
    // RENDER FUNCTIONS
    // =========================================================================
    const renderDragOverlay = () => (
        <DashedBorder
            colour={Colour["border-primary"]}
            thickness={Border["width-040"]}
            radius={Radius["sm"]}
            enabled={border}
            backgroundColor={Colour["bg-primary-subtler"]}
            className={styles.dragOverlay}
        >
            <CloudArrowUpFillIcon className={styles.overlayIcon} />
            <Typography.BodyMD className={styles.overlayText} weight="semibold">
                Drop files here
            </Typography.BodyMD>
        </DashedBorder>
    );

    return (
        <DashedBorder
            id={id}
            data-testid={testId || "dropzone"}
            enabled={border}
            thickness={Border["width-040"]}
            radius={Radius["sm"]}
            colour={Colour["border"]}
            className={clsx(
                styles.container,
                border && styles.containerWithDashedBorder,
                className
            )}
            {...getRootProps()}
        >
            <input
                type="file"
                name={name}
                ref={inputRef}
                tabIndex={-1}
                aria-hidden
                className={styles.hiddenInput}
                accept={accept}
                capture={capture}
                multiple={multiple}
                data-testid={testId ? `${testId}-input` : "dropzone-input"}
                onChange={handleChange}
            />
            {children}
            {isDragActive && renderDragOverlay()}
        </DashedBorder>
    );
};

export const FileUploadDropzone = forwardRef(Component);
